/// Merges overlapping intervals in a vector of tuples.
///
/// # Arguments
/// * `intervals` - A vector of tuples where each tuple represents an interval (start, end).
///
/// # Returns
/// A new vector of tuples where all overlapping intervals have been merged.
/// Each merged interval is represented by the minimum start and maximum end of the overlapping intervals.
///
/// # Examples
/// ```
/// let intervals = vec![(1, 3), (2, 6), (8, 10), (15, 18)];
/// let merged = merge_intervals(intervals);
/// assert_eq!(merged, vec![(1, 6), (8, 10), (15, 18)]);
/// ```
pub fn merge_intervals(mut intervals: Vec<(i32, i32)>) -> Vec<(i32, i32)> {
    if intervals.is_empty() {
        return intervals;
    }
    intervals.sort_by(|a, b| a.0.cmp(&b.0));
    let mut merged = Vec::new();
    let mut current = intervals[0];
    for interval in intervals.into_iter().skip(1) {
        if current.1 >= interval.0 {
            current.1 = current.1.max(interval.1);
        } else {
            merged.push(current);
            current = interval;
        }
    }
    merged.push(current);
    merged
}
